def hash_password(password, salt=None):
    """Hash password with salt using PBKDF2."""
    if salt is None:
        salt = os.urandom(32)
    key = hashlib.pbkdf2_hmac('sha256', password.encode(), salt, 100000)
    return salt + key


def verify_password(stored_hash, password):
    """Verify password against stored hash."""
    salt = stored_hash[:32]
    stored_key = stored_hash[32:]
    key = hashlib.pbkdf2_hmac('sha256', password.encode(), salt, 100000)
    return hmac.compare_digest(stored_key, key)


def generate_totp_secret():
    """Generate a TOTP secret key."""
    return base64.b32encode(os.urandom(20)).decode('utf-8')


def get_totp_token(secret, time_step=30, digits=6):
    """Generate current TOTP token."""
    key = base64.b32decode(secret, casefold=True)
    counter = int(time.time()) // time_step
    counter_bytes = struct.pack('>Q', counter)
    hmac_hash = hmac.new(key, counter_bytes, hashlib.sha1).digest()
    offset = hmac_hash[-1] & 0x0F
    truncated = struct.unpack('>I', hmac_hash[offset:offset + 4])[0]
    truncated &= 0x7FFFFFFF
    code = truncated % (10 ** digits)
    return str(code).zfill(digits)


def verify_totp(secret, token, window=1):
    """Verify TOTP token with a time window."""
    for i in range(-window, window + 1):
        key = base64.b32decode(secret, casefold=True)
        counter = (int(time.time()) // 30) + i
        counter_bytes = struct.pack('>Q', counter)
        hmac_hash = hmac.new(key, counter_bytes, hashlib.sha1).digest()
        offset = hmac_hash[-1] & 0x0F
        truncated = struct.unpack('>I', hmac_hash[offset:offset + 4])[0]
        truncated &= 0x7FFFFFFF
        code = str(truncated % (10 ** 6)).zfill(6)
        if hmac.compare_digest(code, token):
            return True
    return False


