def check_mfa_rate_limit(username):
    """Check if user is rate-limited for MFA attempts."""
    if username in MFA_ATTEMPTS:
        attempts, lockout_time = MFA_ATTEMPTS[username]
        if lockout_time and time.time() < lockout_time:
            return False, lockout_time - time.time()
        if lockout_time and time.time() >= lockout_time:
            MFA_ATTEMPTS[username] = (0, None)
    return True, 0


def record_mfa_attempt(username, success):
    """Record an MFA attempt for rate limiting."""
    if success:
        MFA_ATTEMPTS.pop(username, None)
        return
    current = MFA_ATTEMPTS.get(username, (0, None))
    attempts = current[0] + 1
    if attempts >= MAX_MFA_ATTEMPTS:
        MFA_ATTEMPTS[username] = (attempts, time.time() + MFA_LOCKOUT_DURATION)
    else:
        MFA_ATTEMPTS[username] = (attempts, None)


def require_full_auth(f):
    """Decorator requiring both password AND MFA verification.
    
    This is the secure approach: protected resources require BOTH factors
    to be verified before access is granted. No resources are accessible
    with only password verification.
    """
    @wraps(f)
    def decorated_function(*args, **kwargs):
        if 'user' not in session:
            return jsonify({'error': 'Authentication required', 'redirect': '/login'}), 401

        if not session.get('mfa_verified', False):
            return jsonify({
                'error': 'MFA verification required',
                'redirect': '/verify-mfa',
                'message': 'Please complete two-factor authentication'
            }), 403

        # Verify session integrity
        if not _verify_session_integrity():
            session.clear()
            return jsonify({'error': 'Session integrity check failed', 'redirect': '/login'}), 401

        return f(*args, **kwargs)
    return decorated_function


def require_password_auth(f):
    """Decorator requiring at least password authentication (for MFA page access)."""
    @wraps(f)
    def decorated_function(*args, **kwargs):
        if 'user' not in session:
            return jsonify({'error': 'Authentication required', 'redirect': '/login'}), 401
        if not session.get('password_verified', False):
            return jsonify({'error': 'Password verification required', 'redirect': '/login'}), 401
        return f(*args, **kwargs)
    return decorated_function


def _generate_session_token():
    """Generate a cryptographically secure session token."""
    return secrets.token_hex(32)


def _verify_session_integrity():
    """Verify session hasn't been tampered with."""
    if 'session_token' not in session or 'user' not in session:
        return False
    # Check session hasn't expired
    if 'session_created' in session:
        if time.time() - session['session_created'] > app.config['PERMANENT_SESSION_LIFETIME']:
            return False
    return True


