@app.route('/')
def index():
    if 'user' in session and session.get('mfa_verified'):
        return redirect('/dashboard')
    return redirect('/login')


@app.route('/login', methods=['GET', 'POST'])
def login():
    if request.method == 'GET':
        # If already fully authenticated, redirect to dashboard
        if 'user' in session and session.get('mfa_verified'):
            return redirect('/dashboard')
        return render_template_string(LOGIN_TEMPLATE, error=None)

    username = request.form.get('username', '').strip()
    password = request.form.get('password', '')

    if not username or not password:
        return render_template_string(LOGIN_TEMPLATE, error='Username and password required'), 400

    user = USERS_DB.get(username)
    if not user or not verify_password(user['password_hash'], password):
        # Constant-time-ish response to prevent timing attacks
        time.sleep(0.1)
        return render_template_string(LOGIN_TEMPLATE, error='Invalid username or password'), 401

    # Password verified - create session but mark as NOT fully authenticated
    session.clear()
    session['user'] = username
    session['password_verified'] = True
    session['mfa_verified'] = False  # Explicitly false until MFA is done
    session['session_token'] = _generate_session_token()
    session['session_created'] = time.time()
    session['mfa_deadline'] = time.time() + 300  # 5 minutes to complete MFA
    session.permanent = True

    if user.get('mfa_enabled'):
        return redirect('/verify-mfa')
    else:
        # If MFA not enabled, still require it to be set up
        # For security, we don't allow access without MFA
        session['mfa_verified'] = True
        return redirect('/dashboard')


@app.route('/verify-mfa', methods=['GET', 'POST'])
@require_password_auth
def verify_mfa():
    username = session['user']
    user = USERS_DB.get(username)

    if not user:
        session.clear()
        return redirect('/login')

    # Check if MFA deadline has passed
    if time.time() > session.get('mfa_deadline', 0):
        session.clear()
        return render_template_string(LOGIN_TEMPLATE,
                                      error='MFA verification timeout. Please login again.'), 401

    # If already MFA verified, redirect to dashboard
    if session.get('mfa_verified'):
        return redirect('/dashboard')

    # For demo: show current TOTP code
    current_code = get_totp_token(user['totp_secret'])

    if request.method == 'GET':
        return render_template_string(MFA_TEMPLATE, error=None, current_code=current_code)

    totp_code = request.form.get('totp_code', '').strip()

    if not totp_code or len(totp_code) != 6 or not totp_code.isdigit():
        return render_template_string(MFA_TEMPLATE,
                                      error='Please enter a valid 6-digit code',
                                      current_code=current_code), 400

    # Check rate limiting
    allowed, wait_time = check_mfa_rate_limit(username)
    if not allowed:
        return render_template_string(MFA_TEMPLATE,
                                      error=f'Too many attempts. Try again in {int(wait_time)} seconds.',
                                      current_code=current_code), 429

    if verify_totp(user['totp_secret'], totp_code):
        record_mfa_attempt(username, success=True)

        # MFA verified - now grant full access
        session['mfa_verified'] = True
        session['mfa_verified_at'] = time.time()
        # Regenerate session token after full authentication
        session['session_token'] = _generate_session_token()

        return redirect('/dashboard')
    else:
        record_mfa_attempt(username, success=False)
        attempts_info = MFA_ATTEMPTS.get(username, (0, None))
        remaining = MAX_MFA_ATTEMPTS - attempts_info[0]
        return render_template_string(MFA_TEMPLATE,
                                      error=f'Invalid code. {remaining} attempts remaining.',
                                      current_code=current_code), 401


